import React from 'react';

interface Log {
    id: string;
    msg: string;
    timestamp: string;
}

export const SystemTerminal: React.FC<{ logs?: Log[] }> = ({ logs = [] }) => {
    return (
        <footer className="border-t border-[#2A2A2A] bg-black py-2 px-4 overflow-hidden mt-auto">
            <div className="flex whitespace-nowrap text-[10px] font-mono text-slate-400 gap-8 animate-marquee">
                <span className="font-bold tracking-[0.2em] text-white/40 uppercase">SYSTEM_LOGS:</span>

                <span className="text-white uppercase">&gt;&gt; ROUTING OPTIMIZED [NODE_ALPHA]</span>
                <span className="text-[#FF3B30] uppercase font-bold">&gt;&gt; ANOMALY DETECTED IN NODE_04</span>
                <span className="uppercase font-mono">&gt;&gt; TELEMETRY SYNC COMPLETE</span>
                <span className="uppercase font-mono">&gt;&gt; LATENCY 12MS</span>
                <span className="text-white uppercase font-bold">&gt;&gt; ROUTING OPTIMIZED [NODE_BETA]</span>
                <span className="uppercase font-mono">&gt;&gt; SYSTEM_READY [STABLE]</span>

                {/* Repeat for seamless loop effect */}
                <span className="text-white uppercase">&gt;&gt; ROUTING OPTIMIZED [NODE_ALPHA]</span>
                <span className="text-[#FF3B30] uppercase font-bold">&gt;&gt; ANOMALY DETECTED IN NODE_04</span>
            </div>
        </footer>
    );
};
